CREATE TABLE lead_forms (id uuid PRIMARY KEY DEFAULT concourse.uuid_generate_v7(), event_exhibitor_id uuid NOT NULL REFERENCES event_exhibitors(id) ON DELETE CASCADE, name text NOT NULL, description text, is_default boolean NOT NULL DEFAULT false, status text NOT NULL DEFAULT 'active', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT lead_forms_status_check CHECK (status IN ('active','archived')));
CREATE UNIQUE INDEX lead_forms_exhibitor_name_key ON lead_forms(event_exhibitor_id, name); CREATE INDEX lead_forms_event_exhibitor_id_idx ON lead_forms(event_exhibitor_id);
CREATE TABLE lead_form_fields (id uuid PRIMARY KEY DEFAULT concourse.uuid_generate_v7(), lead_form_id uuid NOT NULL REFERENCES lead_forms(id) ON DELETE CASCADE, key text NOT NULL, label text NOT NULL, type text NOT NULL, required boolean NOT NULL DEFAULT false, placeholder text, default_value jsonb, validation jsonb NOT NULL DEFAULT '{}'::jsonb, sort_order integer NOT NULL, help_text text, visibility_condition jsonb, status text NOT NULL DEFAULT 'active', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT lead_form_fields_status_check CHECK (status IN ('active','archived')));
CREATE UNIQUE INDEX lead_form_fields_form_key_key ON lead_form_fields(lead_form_id, key); CREATE UNIQUE INDEX lead_form_fields_form_order_key ON lead_form_fields(lead_form_id, sort_order); CREATE INDEX lead_form_fields_lead_form_id_idx ON lead_form_fields(lead_form_id);
GRANT SELECT, INSERT, UPDATE ON lead_forms, lead_form_fields TO app_tenant; GRANT ALL PRIVILEGES ON lead_forms, lead_form_fields TO app_platform;
ALTER TABLE lead_forms ENABLE ROW LEVEL SECURITY; ALTER TABLE lead_forms FORCE ROW LEVEL SECURITY; CREATE POLICY tenant_isolation ON lead_forms USING (event_exhibitor_id IN (SELECT id FROM event_exhibitors WHERE organization_id = current_setting('app.current_org_id', true)::uuid)) WITH CHECK (event_exhibitor_id IN (SELECT id FROM event_exhibitors WHERE organization_id = current_setting('app.current_org_id', true)::uuid));
ALTER TABLE lead_form_fields ENABLE ROW LEVEL SECURITY; ALTER TABLE lead_form_fields FORCE ROW LEVEL SECURITY; CREATE POLICY tenant_isolation ON lead_form_fields USING (lead_form_id IN (SELECT id FROM lead_forms)) WITH CHECK (lead_form_id IN (SELECT id FROM lead_forms));
